import{_ as a,c as s,o as i,a4 as t}from"./chunks/framework.nQaBHiNx.js";const u=JSON.parse('{"title":"第六章 写出言简意赅的注释","description":"","frontmatter":{"permalink":"/note/the-art-of-readable-code/06.html"},"headers":[],"relativePath":"computer/book/the-art-of-readable-code/06-第六章 写出言简意赅的注释.md","filePath":"computer/book/the-art-of-readable-code/06-第六章 写出言简意赅的注释.md"}'),e={name:"computer/book/the-art-of-readable-code/06-第六章 写出言简意赅的注释.md"},l=t(`<h1 id="第六章-写出言简意赅的注释" tabindex="-1">第六章 写出言简意赅的注释 <a class="header-anchor" href="#第六章-写出言简意赅的注释" aria-label="Permalink to &quot;第六章 写出言简意赅的注释&quot;">​</a></h1><p>如果你要写注释，最好把它写得精确——越明确和细致越好。另外，由于注释在屏幕上也要占很多的地方,并且需要花更多的时间来读，因此，注释也需要很紧凑。</p><div class="tip custom-block"><p class="custom-block-title">关键思想</p><p>注释应当有很高的信息/空间率。</p></div><h2 id="让注释保持紧凑" tabindex="-1">让注释保持紧凑 <a class="header-anchor" href="#让注释保持紧凑" aria-label="Permalink to &quot;让注释保持紧凑&quot;">​</a></h2><p>下面的例子是一个 C++ 类型定义的注释</p><div class="language-cpp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// The int is the CatagoryType.</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Hte first float in the inner pair is the &#39;score&#39;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// the second is the &#39;weight&#39;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">type of hash_map</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, pair</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;float</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">float&gt;&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ScoreMap;</span></span></code></pre></div><p>可是为什么解释这个例子要用三行呢？用一行不就可以了吗？</p><div class="language-cpp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// CategoryType -&gt; (score, weight)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">type of hash_map</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, pair</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;float</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">float&gt;&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ScoreMap;</span></span></code></pre></div><h2 id="避免使用不明确的代词" tabindex="-1">避免使用不明确的代词 <a class="header-anchor" href="#避免使用不明确的代词" aria-label="Permalink to &quot;避免使用不明确的代词&quot;">​</a></h2><h2 id="润色粗糙的句子" tabindex="-1">润色粗糙的句子 <a class="header-anchor" href="#润色粗糙的句子" aria-label="Permalink to &quot;润色粗糙的句子&quot;">​</a></h2><h2 id="精确地描述函数的行为" tabindex="-1">精确地描述函数的行为 <a class="header-anchor" href="#精确地描述函数的行为" aria-label="Permalink to &quot;精确地描述函数的行为&quot;">​</a></h2><h2 id="用输入、输出例子来说明特别的情况" tabindex="-1">用输入、输出例子来说明特别的情况 <a class="header-anchor" href="#用输入、输出例子来说明特别的情况" aria-label="Permalink to &quot;用输入、输出例子来说明特别的情况&quot;">​</a></h2><p>对于注释来讲，一个精心挑选的输入/输出例子比千言万语还有效。</p><p>例如，下面是一个用来移除部分字符串的通用函数:</p><div class="language-java vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Remote the suffix / prefix of &quot;chars&quot; from the input src</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">String </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Strip</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(String src, String chars) { ... }</span></span></code></pre></div><p>这条注释不是很精确,因为它不能回答下列问题：</p><ul><li>chars 是整个要移除的子串，还是一组无序的字母?</li><li>如果在 src 的结尾有多个 chars 会怎样?</li></ul><p>然而一个精心挑选的例子就可以回答这些问题：</p><div class="language-java vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Example: Strip(&quot;/abba/a/ba&quot;, &quot;ba&quot;) return &quot;/a/&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">String </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Strip</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(String src, String chars) { ... }</span></span></code></pre></div><p>这个例子展示了Strip()的整个动能。请注意,如果一个更简单的示例不能回答这些问题的话,它就不会那么有用</p><div class="language-java vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Example: Strip(&quot;ab&quot;, &quot;a&quot;) return &quot;b&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">String </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Strip</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(String src, String chars) { ... }</span></span></code></pre></div><h2 id="声明代码的意图" tabindex="-1">声明代码的意图 <a class="header-anchor" href="#声明代码的意图" aria-label="Permalink to &quot;声明代码的意图&quot;">​</a></h2><h2 id="具名函数参数-的注释" tabindex="-1">“具名函数参数”的注释 <a class="header-anchor" href="#具名函数参数-的注释" aria-label="Permalink to &quot;“具名函数参数”的注释&quot;">​</a></h2><h2 id="采用信息量高的词" tabindex="-1">采用信息量高的词 <a class="header-anchor" href="#采用信息量高的词" aria-label="Permalink to &quot;采用信息量高的词&quot;">​</a></h2><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>本章是关于如果把更多的信息装入更小的空间里。下面是一些具体的提示：</p><ul><li>当像 it 和 this 这样的代词可能指代很多个事物时，避免使用它们。</li><li>尽量精确的描述函数的行为。</li><li>在注释中用精心挑选的输入/输出例子进行说明</li><li>声明代码的高层次意图，而非明显的细节</li><li>用嵌入的注释来解释难以理解的函数参数</li><li>用含义丰富的词来时注释简洁</li></ul>`,27),h=[l];function n(p,r,o,c,d,k){return i(),s("div",null,h)}const E=a(e,[["render",n]]);export{u as __pageData,E as default};
